const t={INTRO:{title:"La Demande",lines:[{speaker:"Delphine",text:"J'ai une carte de la plantation et, pour l'instant, je ne connais que le bureau comme emplacement.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"On m'a fourni des photos de toutes les personnes connues pour être présentes sur les lieux à ce moment-là.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"mais je n'ai que les noms du père et de la sœur de mon bienfaiteur. Je vais devoir découvrir les noms des autres invités avant de pouvoir commencer à me connecter à eux.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Bon, allons au bureau et voyons ce que nous pouvons trouver.",portrait:"portraits/investigator.png"}]},STUDY_ZERO:{title:"Souvenirs Ancrés",lines:[{speaker:"Delphine",text:"Je peux ressentir l'essence du bureau lorsque je me concentre dessus. C'est presque comme si j'étais dans la pièce. Ce sentiment est impossible à décrire et beaucoup pensent que ce n'est pas réel, juste un tour de passe-passe. Je ne leur en veux pas.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Il y a une atmosphère particulière dans les vieilles pièces. Les objets qui forment l'essence de l'espace finissent par faire partie de la pièce. Les objets qui restent assez longtemps dans cet espace s'y ancrent.",portrait:"portraits/investigator.png"},{speaker:" ",text:"Delphine peut se concentrer sur ces objets, comme le téléphone ici présent, à condition que le propriétaire ait été identifié et que son aura soit attachée sur l'objet."},{speaker:" ",text:"Vous pouvez vous vous synchroniser sur le téléphone en lui attribuant le bon propriétaire."}]},LINES:{lines:[{speaker:"Delphine",text:"Un camp militaire temporaire aurait été appelé les 'lines' (lignes). Il aurait été constitué de huttes faites de matériaux locaux au lieu de tentes.",portrait:"portraits/investigator.png"}]},STUDY_ONE:{title:"Échos du Bureau",lines:[{speaker:"Delphine",text:"Je sais que Jeremiah était seul à 16h dans le bureau. Si je me concentre assez fort sur Jeremiah, je devrais être capable de voir l'écho de ce qui s'y est passé.",portrait:"portraits/investigator.png"},{speaker:" ",text:"Réglez la chronologie sur 16h00 et placez la photo de Jeremiah en focus."}]},STUDY_11:{title:"L'Appel Téléphonique",branches:[{check:e=>!e.unlockedPeople.has("p10"),lines:[{speaker:"Delphine",text:"Il y a un Jiro dans la pièce aux côtés de Kanan. Je devrais revenir ici une fois que j'aurai découvert qui il est, pour voir sa version de cette conversation.",portrait:"portraits/investigator.png"}]},{check:e=>e.unlockedPeople.has("p10"),lines:[{speaker:"Delphine",text:"Je sais maintenant que Jiro et Kanan étaient tous deux dans le bureau ici. Je peux débloquer l'écho complet en me concentrant sur eux deux.",portrait:"portraits/investigator.png"}]}]},STUDY_11_2:{title:"L'Appel Téléphonique",lines:[{speaker:"Delphine",text:"Il y a un Jiro dans la pièce aux côtés de Kanan. Je devrais revenir ici une fois que j'aurai découvert qui il est, pour voir sa version de cette conversation.",portrait:"portraits/investigator.png"}]},DEDUCTION_HELP:{title:"Une Nouvelle Stratégie",lines:[{speaker:"Delphine",text:"Deux inconnus... J'ai leurs photos et maintenant leurs noms. Je dois me rappeler que les populations indigènes de Bornéo n'ont souvent pas de nom de famille, donc je devrais pouvoir identifier Kanan avec juste son prénom.",portrait:"portraits/investigator.png"},{speaker:" ",text:"Si Delphine arrive à deviner qui ils sont d'après le contexte, elle peut attribuer un nom à leur visage dans le dossier des Invités."}]},TELEPHONE_0:{title:"Téléphone à Manivelle",lines:[{speaker:"Delphine",text:"Ce téléphone a une forte énergie. Je peux clairement sentir qu'il est utilisé à 2 heures du matin par un homme avec un accent de Bornéo.",portrait:"portraits/investigator.png"},{speaker:" ",text:"Maintenant que l'aura de Delphine est attachée au téléphone, elle peut ressentir la personne qui l'utilise à n'importe quel moment."},{speaker:" ",text:"Mais elle ne peut entendre et ressentir que la personne qui utilise ou tient l'objet, et personne d'autre dans la pièce."}]},GHOST_IMAGE:{title:"L'Image Fantôme",lines:[{speaker:"Delphine",text:"Mon Dieu ! Ce flash... cette image dans le miroir...",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"C'était faible, mais l'empreinte psychique est indéniable.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"La formidable intensité du flash a laissé une marque sur l'éther. C'est assez fort.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Avec cet ancrage, je peux le suivre. Je peux maintenant ressentir ses mouvements à travers la plantation.",portrait:"portraits/investigator.png"}]},SHAMAN_NAME:{title:"Le Chaman",lines:[{speaker:"Delphine",text:"Babalian Antau... Un puissant Chaman.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Je doute de pouvoir trouver une photo de lui. Il est trop obscur, trop caché dans les ombres de l'histoire.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Je devrai déduire sa présence par d'autres moyens. Je vais devoir faire preuve d'ingéniosité si je veux pouvoir reconstituer ses mouvements.",portrait:"portraits/investigator.png"}]},TUAN_BESAR:{title:"Le Tuan",theme:"british_standards",lines:[{speaker:"Delphine",text:"Dans ces plantations, 'Tuan' est le titre habituel pour s'adresser aux officiels. Le 'Tuan Besar', ou 'Grand Maître', est le dirigeant responsable de l'ensemble du domaine. Dans ce cas précis, Kanan fait référence à Jeremiah Goodwill.",portrait:"portraits/investigator.png"}]},MEM:{title:"La Mem",theme:"british_standards",lines:[{speaker:"Delphine",text:"Mem est un titre spécifique pour la 'Maîtresse de Maison'. Je suppose que 'Petite Mem' est un terme affectueux utilisé par les domestiques pour désigner Lune.",portrait:"portraits/investigator.png"}]},CONSTABULARY:{title:"La Gendarmerie",theme:"maritime_rules",lines:[{speaker:"Delphine",text:"La branche maritime (Marine Wing) de la North Borneo Armed Constabulary est l'équivalent d'une garde côtière dans les territoires britanniques du Bornéo du Nord. Ils utilisaient de petites chaloupes à moteur armées qui patrouillaient sur les côtes avant l'invasion japonaise.",portrait:"portraits/investigator.png"}]},PIRACY_GRILLE:{theme:"piracy",title:"La Grille",lines:[{speaker:"Delphine",text:"La menace d'un détournement par des pirates était si courante que les navires à vapeur des années 1920 étaient équipés de grilles anti-piraterie, de lourdes barres en fer et de portes séparant la passerelle et les quartiers de première classe du reste du navire, transformant essentiellement la zone des officiers en forteresse.",portrait:"portraits/investigator.png"}]},GAYUNG:{title:"Gayung",theme:"british_standards",lines:[{speaker:"Delphine",text:"Un Gayung est une louche traditionnelle en plastique ou en métal, utilisée avec une jarre ou un seau pour prendre son bain.",portrait:"portraits/investigator.png"}]},SHANGAI_JAR:{title:"Jarre de Shanghai",theme:"british_standards",lines:[{speaker:"Delphine",text:"Les grandes jarres en céramique de Shanghai sont couramment utilisées dans les maisons coloniales pour stocker de l'eau fraîche pour le bain sous la chaleur tropicale.",portrait:"portraits/investigator.png"}]},FEVER:{title:"La Fièvre",theme:"tropical_killers",lines:[{speaker:"Delphine",text:"Lune doit vouloir parler de la fièvre bilieuse hémoglobinurique (Blackwater fever), de loin la cause de mortalité la plus redoutée parmi les jeunes Européens sous les tropiques. C'est une complication terrifiante due aux infections répétées de paludisme et qui est mortelle en quelques jours.",portrait:"portraits/investigator.png"}]},STARCHED_WHITES:{title:"Vêtements Blancs Empesés",theme:"british_standards",lines:[{speaker:"Delphine",text:"Les vêtements blancs empesés sont la tenue standard des hommes dans les maisons coloniales. Un short blanc empesé, des chaussettes blanches montantes et une chemise blanche, ils sont propres et repassés, et sentent souvent la lavande ou d'autres parfums similaires. Ce n'est pas très pratique pour travailler, mais c'est utilisé pour maintenir une illusion mal conçue de la supériorité britannique.",portrait:"portraits/investigator.png"}]},SABAH:{title:"Sabah",theme:"colonies",lines:[{speaker:"Delphine",text:"Le Sabah est le plus grand État de Bornéo. Il est bordé par le Sarawak et le Kalimantan à l'ouest, et les Philippines à l'est. Il est dirigé par la British North Borneo Chartered Company, une compagnie privée à laquelle le gouvernement britannique a accordé une charte royale au 19ème siècle.",portrait:"portraits/investigator.png"}]},SUNDOWNER:{title:"Sundowner",theme:"culture",lines:[{speaker:"Delphine",text:"Mes recherches montrent qu'un 'Sundowner' est un terme familier local pour se référer à un verre du soir, pris au coucher du soleil pour marquer le passage de la chaleur diurne à la fraîcheur nocturne.",portrait:"portraits/investigator.png"}]},GIN_PAHITS:{title:"Gin Pahits",theme:"culture",lines:[{speaker:"Delphine",text:"Le Gin Pahit est un gin mélangé avec plusieurs grosses gouttes de bitters d'Angostura, ce qui aide à soulager l'estomac après une journée passée dans l'humidité de la jungle.",portrait:"portraits/investigator.png"}]},SMALL_CHOPS:{title:"Petits En-cas",theme:"culture",lines:[{speaker:"Delphine",text:"Les 'Small Chops' est un terme local pour les amuse-gueules servis avec les Sundowners. Ils sont conçus pour être salés et épicés afin de stimuler le palais et d'encourager à boire.",portrait:"portraits/investigator.png"}]},TOBACCO_TRADE_IS_DRYING_UP:{title:"Le Commerce du Tabac se Tarit",theme:"colonies",lines:[{speaker:"Delphine",text:"Il y a 30 ans, le Bornéo du Nord était mondialement connu pour ses feuilles d'enveloppe de cigares de haute qualité. Cependant, à partir des années 1930, de nombreuses compagnies de tabac ont commencé à fermer ou à se tourner vers le caoutchouc et la noix de coco en raison de la popularité croissante de la cigarette et de l'épuisement des sols. Il semble que les Goodwill aient pris du retard et en subissent les conséquences.",portrait:"portraits/investigator.png"}]},BAJAU:{title:"Les Bajaus",theme:"pearls",lines:[{speaker:"Delphine",text:"Les Bajaus sont un peuple nomade de la mer qui vit dans les eaux autour de Bornéo. Ce sont des plongeurs incroyables et des experts en perles.",portrait:"portraits/investigator.png"}]},TOWKAY:{title:"Les Towkays",theme:"pearls",lines:[{speaker:"Delphine",text:"Les Towkays chinois sont des marchands puissants et influents qui contrôlaient le commerce des perles dans le Bornéo du Nord avant la guerre.",portrait:"portraits/investigator.png"}]},KORNBRAND:{title:"Kornbrand",theme:"culture",lines:[{speaker:"Delphine",text:"Le Kornbrand est une marque allemande de spiritueux à base de céréales très similaire à la vodka, mais souvent distillé à un degré un peu plus bas pour conserver le goût des céréales. Pour un observateur britannique, cela peut ressembler à de la vodka, mais pour un Allemand ou un Russe, la distinction est vitale.",portrait:"portraits/investigator.png"}]},SUNNING:{title:"Le Sunning",theme:"piracy",lines:[{speaker:"Delphine",text:"Le Sunning était un navire à vapeur qui a été détourné par des pirates en 1926.",portrait:"portraits/investigator.png"}]},TUAN_DOSE:{title:"La Dose du Tuan",theme:"tropical_killers",lines:[{speaker:"Delphine",text:"La quinine était généralement prise quotidiennement avec le Sundowner et un encas en soirée, car on pensait qu'elle ne devait pas être prise l'estomac vide. Presque tous les habitants de Bornéo en prennent tous les jours pour lutter contre la malaria.",portrait:"portraits/investigator.png"}]},QUININE:{title:"La Quinine",theme:"tropical_killers",lines:[{speaker:"Delphine",text:"La quinine était généralement prise quotidiennement avec le Sundowner et un encas en soirée, car on pensait qu'elle ne devait pas être prise l'estomac vide. Presque tous les habitants de Bornéo en prennent tous les jours pour lutter contre la malaria.",portrait:"portraits/investigator.png"}]},SALLOW:{title:"Teint Cireux",theme:"tropical_killers",lines:[{speaker:"Delphine",text:"Le terme 'Sallow' (cireux) est utilisé pour décrire la peau jaunâtre qui se développe sur le visage et les mains des Européens ayant contracté le paludisme. C'est un signe de maladie chronique.",portrait:"portraits/investigator.png"}]},BIAS_BAY:{title:"La Baie de Bias",theme:"piracy",lines:[{speaker:"Delphine",text:"La baie de Bias est une crique cachée sur la côte du Guangdong, qui servit de république pirate durant l'âge d'or de la piraterie.",portrait:"portraits/investigator.png"}]},STRAITS_STEAMSHIP:{title:"Le Navire à Vapeur des Détroits",theme:"the_seas",lines:[{speaker:"Delphine",text:"Le navire à vapeur de la Straits Steamship Company était la principale route utilisée par les Goodwill pour transporter marchandises et personnes du continent vers Bornéo. C'était un trajet régulier, mais c'était aussi une cible pour les pirates.",portrait:"portraits/investigator.png"}]},SANDAKAN:{title:"Sandakan",theme:"colonies",lines:[{speaker:"Delphine",text:"Sandakan était la capitale du Bornéo du Nord britannique et la plus grande ville de la région. C'était un lieu de contrastes extrêmes : un centre administratif britannique sophistiqué entouré d'une vaste jungle sauvage et d'une mer sans loi. La ville fut complètement détruite à la fin de la guerre.",portrait:"portraits/investigator.png"}]},KACHANG:{theme:"culture",lines:[{speaker:"Delphine",text:"Kachang signifie 'haricot' ou 'noix' en malais. Généralement des cacahuètes grillées avec des épices.",portrait:"portraits/investigator.png"}]},BLACK_SMOKE:{theme:"japanese_invasion",lines:[{speaker:"Delphine",text:"Lorsque l'invasion japonaise fut imminente, les Hollandais ont fait exploser les raffineries de pétrole et mis le feu aux puits de Miri et de Balikpapan. Pendant des semaines, le ciel au-dessus de Bornéo fut taché de noir.",portrait:"portraits/investigator.png"}]},CHANDU:{theme:"opium",lines:[{speaker:"Delphine",text:"Le Chandu est de l'opium raffiné, bouilli et fermenté en une pâte semblable à de la mélasse. C'était un monopole gouvernemental dans de nombreuses colonies.",portrait:"portraits/investigator.png"}]},DROSS:{theme:"opium",lines:[{speaker:"Delphine",text:"Le Dross est le résidu toxique, semblable à du charbon de bois, qui reste après avoir fumé de l'opium. Il est souvent gratté et remélangé avec de l'opium frais, ou consommé par les toxicomanes qui n'ont pas les moyens de se payer du Chandu raffiné.",portrait:"portraits/investigator.png"}]},LAMP:{lines:[{speaker:"Delphine",text:"Une lampe Tilley, la lampe à pression à paraffine standard des colonies britanniques.",portrait:"portraits/investigator.png"}]},KOTA_BHARU:{title:"Kota Bharu",lines:[{speaker:"Delphine",text:"Kota Bharu, dans le nord-est de la Malaisie, était un point militaire crucial et le site de la première bataille majeure de la guerre du Pacifique.",portrait:"portraits/investigator.png"}]},RUNDUM_REBELLION:{title:"La Rébellion de Rundum",theme:"colonies",lines:[{speaker:"Delphine",text:"La rébellion de Rundum de 1915 fut le dernier soulèvement majeur du peuple Murut contre la British North Borneo Chartered Company. Elle fut déclenchée par les politiques fiscales de la compagnie et le travail forcé.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Les Muruts, célèbres pour leurs sarbacanes ou 'sumpitans', construisirent des forts souterrains complexes dans les jungles denses de l'intérieur. Pour les jeunes officiers coloniaux, combattre un ennemi invisible sur son propre territoire fut une expérience terrifiante.",portrait:"portraits/investigator.png"}]},TUJU:{title:"Le Tuju",theme:"occult",lines:[{speaker:"Delphine",text:"Le Tuju est une malédiction par laquelle un chaman, le Bomoh, envoie par magie un objet dans le corps d'une victime pour la tuer.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:`La victime souffre d'une agonie soudaine et inexplicable (les "coups de poignard" ou les "tremblements") et la médecine occidentale n'y trouve aucune anomalie. C'est un concept terrifiant, qui mêle la guerre psychologique à une superstition profondément ancrée.`,portrait:"portraits/investigator.png"}]},AISYAH_NAME:{title:"La Servante",lines:[{speaker:"Delphine",text:"Aisyah... Ce doit être la servante de mon tas de photos.",portrait:"portraits/investigator.png",action:"unlock_p11"}]},PIRATE_CAPTAIN:{title:"Le Capitaine Pirate",lines:[{speaker:"Delphine",text:"(Pensée) Cet homme... Ludwig Harrow. Il se comporte comme un roi, pas comme un simple bandit. Est-il assez tristement célèbre pour figurer dans les journaux ?",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"(Pensée) De toute façon, je dois appeler Armand à propos de l'appel de détresse sur le téléphone. Je lui demanderai en même temps de vérifier dans les archives pour le Capitaine Harrow.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:`(Au téléphone) Armand ? C'est Delphine. Écoutez bien. J'ai une transcription phonétique d'un appel passé depuis la plantation, en malais. Je me demandais si vous pouviez traduire ? "...Goo-dwill... ma-ti... British... Navy..." ?`,portrait:"portraits/investigator.png"},{speaker:"Armand",text:`(Au téléphone) Delphine... *soupir*. Mon malais est rouillé, mais "mati" signifie mort. On dirait qu'il affirmait que Jeremiah Goodwill avait été assassiné par des pirates et demandait l'assistance immédiate de la Marine Britannique. Ils devaient arriver le lendemain matin à 9 heures.`,portrait:"portraits/armand.jpeg"},{speaker:"Delphine",text:"Efficace. Il a dépeint un massacre pour s'assurer d'une réponse rapide et meurtrière.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"J'ai une autre demande pendant que je vous tiens. Cela va vous paraître très étrange, mais supportez-le. Le chef de ces pirates était un homme nommé Ludwig Harrow. J'espérais, contre toute attente, qu'il puisse y avoir des informations sur lui quelque part.",portrait:"portraits/investigator.png"},{speaker:"Armand",text:"(Au téléphone) Harrow ? Surprenant. C'est une légende, Delphine. Pas pour sa piraterie, mais pour la guerre. Il a dirigé une unité de guérilla contre l'occupation japonaise. Il a sauvé des centaines de personnes des marches de la mort de Sandakan.",portrait:"portraits/armand.jpeg"},{speaker:"Armand",text:"(Au téléphone) C'est un héros dans les livres d'histoire. Le trouver ici, jouant le rôle du méchant avant l'heure... c'est fascinant. J'ai sa photo de service tirée des archives. Je vais vous l'envoyer.",portrait:"portraits/armand.jpeg",action:"unlock_p13"},{speaker:"Delphine",text:"C'est incroyable. Merci beaucoup, Armand.",portrait:"portraits/investigator.png"}]},EPILOGUE:{title:"Affaire Classée",lines:[{speaker:"Delphine",text:"Nous y sommes parvenus, M. Goodwill. Les esprits ont parlé, et la vérité est enfin mise au jour.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Votre sœur Lune n'a pas péri dans les flammes. Elle a survécu à cette nuit-là. Elle s'est échappée de la plantation avec Lucas Sterling et j'espère qu'elle a refait sa vie ici, en Angleterre.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Elle a choisi de disparaître non pas par peur, mais pour survivre. Pour prendre un nouveau départ.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"J'espère que cela vous apportera la paix que vous cherchez depuis si longtemps. Nous pouvons clore l'affaire si vous le souhaitez, mais je crois qu'il reste encore beaucoup à découvrir.",portrait:"portraits/investigator.png",action:"credits"}]},IRON_ROAD:{title:"La Route de Fer",theme:"colonies",lines:[{speaker:"Delphine",text:"Le chemin de fer du Bornéo du Nord (North Borneo Railway) était un projet typiquement britannique. C'était l'unique réseau ferroviaire de toute l'île. Les plantations le long de la côte ont été conçues pour se connecter à cette ligne. Le chemin de fer servait également à transporter les marchandises depuis et vers le port de Sandakan.",portrait:"portraits/investigator.png"}]},BROOKE_RAJAHS:{title:"Les Rajahs Brooke",theme:"colonies",lines:[{speaker:"Delphine",text:"La partie britannique de Bornéo était divisée en trois territoires : le Sarawak, dirigé par la famille Brooke, connus sous le nom de Rajahs Blancs ; le Bornéo du Nord britannique, dirigé par la British North Borneo Chartered Company ; et Brunei, un protectorat britannique où le Sultan régnait encore.",portrait:"portraits/investigator.png"}]},HALE_ROCKETS:{title:"Les Fusées Hale",theme:"japanese_invasion",lines:[{speaker:"Delphine",text:"Les fusées Hale étaient une série de roquettes développées par les Britanniques. Elles étaient conçues pour être tirées depuis le sol et furent utilisées pour attaquer les positions japonaises. Les fusées Hale étaient des armes redoutables, utilisées par les Britanniques dans de nombreuses batailles.",portrait:"portraits/investigator.png"}]},TRIAD:{title:"La Triade",theme:"opium",lines:[{speaker:"Delphine",text:"La Triade chinoise était un empire criminel très organisé à Bornéo qui gérait l'économie illicite de l'île.",portrait:"portraits/investigator.png"}]},BOMOH:{title:"Le Bomoh",theme:"occult",lines:[{speaker:"Delphine",text:"Le Bomoh était le chaman spirituel et médecin de Bornéo. Ils étaient très respectés et souvent appelés pour soigner les malades et les blessés, ainsi que pour accomplir des rituels plus spirituels.",portrait:"portraits/investigator.png"}]},JOURNEY_INTRO:{title:"La Vision se Renforce",lines:[{speaker:"Delphine",text:"La toile des souvenirs est complète. Je sens la résonance se renforcer... elle m'attire au-delà de l'île.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Les survivants : Lucas, Lune et Rose. Je peux voir leur chemin. Ils ne se sont pas contentés de s'échapper ; ils ont enduré un long et éprouvant voyage de retour vers l'Angleterre.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"J'ai débloqué une nouvelle voie. Elle retrace leur voyage de retour. Je peux désormais les suivre à travers l'océan.",portrait:"portraits/investigator.png"}]},COLLYER_QUAY:{title:"Le Quai Collyer",theme:"malaysia",lines:[{speaker:"Delphine",text:"Le quai Collyer (Collyer Quay) est un quartier animé de Singapour. C'est une plaque tournante du commerce et des échanges. Les rues sont bordées de boutiques et de marchés.",portrait:"portraits/investigator.png"}]},SAILORS_HOME:{title:"La Maison des Marins",lines:[{speaker:"Delphine",text:"La Maison des Marins (Sailors Home)",portrait:"portraits/investigator.png"}]},BOLSTER:{title:"Traversin",lines:[{speaker:"Delphine",text:"De longs oreillers fermes très répandus sous les tropiques.",portrait:"portraits/investigator.png"}]},ULU:{title:"L'Ulu",lines:[{speaker:"Delphine",text:"L'Ulu est une forêt tropicale dense de Bornéo.",portrait:"portraits/investigator.png"}]},CAUSEWAY:{title:"La Chaussée",lines:[{speaker:"Delphine",text:"La Chaussée (The Causeway) est un pont reliant Singapour à la Malaisie.",portrait:"portraits/investigator.png"}]},DBS:{title:"DBS",lines:[{speaker:"Delphine",text:"Sujet Britannique en Détresse (DBS - Distressed British Subject) : la catégorie officielle pour les réfugiés britanniques sans moyens de subsistance fuyant l'occupation japonaise.",portrait:"portraits/investigator.png"}]},MALACCA:{title:"Malacca",lines:[{speaker:"Delphine",text:"Une étendue d'eau longue et étroite qui sépare la péninsule malaise de l'île indonésienne de Sumatra.",portrait:"portraits/investigator.png"}]},IPOH:{title:"Ipoh",lines:[{speaker:"Delphine",text:"Une grande ville de Malaisie qui est tombée rapidement durant l'invasion.",portrait:"portraits/investigator.png"}]},KEDAH:{title:"Kedah",lines:[{speaker:"Delphine",text:"Le Kedah est un État situé dans la partie nord-ouest de la Malaisie péninsulaire, frontalier avec la Thaïlande. Fin décembre 1941, le Kedah fut le théâtre d'un désastre stratégique pour les Britanniques. Ce fut la première région continentale de Malaisie à être envahie par les Japonais (le 8 décembre, à peine quelques heures après Pearl Harbor).",portrait:"portraits/investigator.png"}]},BETTY:{title:"Betty",lines:[{speaker:"Delphine",text:"Le nom de code allié pour les bombardiers bimoteurs japonais qui patrouillaient le détroit de Malacca.",portrait:"portraits/investigator.png"}]},NELL:{title:"Nell",lines:[{speaker:"Delphine",text:"Une étendue d'eau longue et étroite qui sépare la péninsule malaise de l'île indonésienne de Sumatra. (Note : Erreur dans le texte original, Nell fait référence aux bombardiers Mitsubishi G3M 'Nell', mais je traduis fidèlement le texte donné ici.)",portrait:"portraits/investigator.png"}]},GALLEFACE:{title:"Le Galle Face",lines:[{speaker:"Delphine",text:"Le Galle Face était le point de repère le plus prestigieux et évocateur de Colombo, à Ceylan. Il se composait de deux parties principales : le Galle Face Green (une vaste promenade en bord de mer) et l'emblématique hôtel Galle Face. Pour Lucas, le Galle Face a probablement représenté la première fois où il s'est vraiment senti de retour à la civilisation.",portrait:"portraits/investigator.png"}]},DUFF:{title:"Duff",lines:[{speaker:"Delphine",text:"Le 'Duff' est un terme d'argot pour désigner le pudding de Noël.",portrait:"portraits/investigator.png"}]},JAGA:{title:"Jaga",lines:[{speaker:"Delphine",text:"Un jaga est un gardien. Des hommes sikhs ou pendjabis étaient couramment employés comme veilleurs de nuit à travers le Bornéo britannique, portant généralement des turbans formels et des tuniques boutonnées à col haut.",portrait:"portraits/investigator.png"}]},FIFTH_COLUMN:{title:"La Cinquième Colonne",theme:"japanese_invasion",lines:[{speaker:"Delphine",text:"La Cinquième Colonne était le nom donné aux activités d'espionnage et de sabotage des forces de l'Axe dans les pays alliés pendant la Seconde Guerre mondiale. Ce terme a été inventé par Winston Churchill pour décrire les efforts de l'Axe visant à saper le moral et l'efficacité des forces alliées.",portrait:"portraits/investigator.png"}]},SIS:{title:"SIS",lines:[{speaker:"Delphine",text:"Le Secret Intelligence Service (SIS) fut la première agence de renseignement du Royaume-Uni. Fondé en 1909, il était responsable de la collecte de renseignements sur les puissances étrangères, en particulier l'Allemagne et l'Union soviétique, ainsi que de la surveillance de la Cinquième Colonne. Il fut rebaptisé plus tard MI6.",portrait:"portraits/investigator.png"}]},SECRETARIAT:{title:"Le Secrétariat Colonial",lines:[{speaker:"Delphine",text:"Les fonctionnaires gérant le gouvernement pour le compte du Gouverneur. À Singapour en 1941, c'était l'autorité suprême pour les visas de sortie, les permis de voyage et les fonds d'urgence pour les réfugiés.",portrait:"portraits/investigator.png"}]},SUMATRA:{title:"Sumatra",lines:[{speaker:"Delphine",text:"Sumatra est la plus grande île d'Indonésie. C'était le joyau des Indes orientales néerlandaises et la principale raison pour laquelle le Japon est entré en guerre dans le Pacifique.",portrait:"portraits/investigator.png"}]},STUKAS:{title:"Stukas",lines:[{speaker:"Delphine",text:"Les Stukas désignent les Junkers Ju 87, un célèbre bombardier en piqué allemand et avion d'attaque au sol utilisé par la Luftwaffe pendant la Seconde Guerre mondiale.",portrait:"portraits/investigator.png"}]},TRAMP_STEAMER:{title:"Cargos Mixtes (Tramp Steamers)",lines:[{speaker:"Delphine",text:"Le 'tramp steamer' (cargo mixte ou vraquier vagabond) était le navire de charge sans gloire de la mer de Chine méridionale, un navire marchand qui errait de port en port à la recherche de cargaisons résiduelles à vendre.",portrait:"portraits/investigator.png"}]},SHOPHOUSE:{title:"Maisons-boutiques (Shop Houses)",lines:[{speaker:"Delphine",text:"Les maisons-boutiques (shophouses) étaient des maisons mitoyennes à deux étages, avec des boutiques au rez-de-chaussée et des espaces d'habitation à l'étage. En 1941, ces bâtiments étaient devenus de véritables labyrinthes de petites cabines intérieures, séparées par de fines cloisons en contreplaqué pour entasser autant de réfugiés en attente d'une issue que possible.",portrait:"portraits/investigator.png"}]},ENDING_INTRO:{title:"Le Dernier Seuil",lines:[{speaker:"Rose",text:"Bonjour. Comment puis-je vous aider ?",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"Madame Sterling ? C'est un plaisir de vous rencontrer enfin.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Vous ne me connaissez pas, mais je sais beaucoup de choses sur vous et votre famille et j'aimerais bien entrer pour vous expliquer.",portrait:"portraits/investigator.png"},{speaker:"Rose",text:"Entrez, entrez. Ne faites pas attention au désordre, j'étais en train de corriger des copies. Je suis institutrice, vous savez.",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"Merci beaucoup.",portrait:"portraits/investigator.png"},{speaker:"Rose",text:"Lune, nous avons de la visite !",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Lune",text:"J'arrive !",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"Lune ! Regarde-toi ! Tu es devenue une si belle jeune femme.",portrait:"portraits/investigator.png"},{speaker:"Lune",text:"Pardon ? Est-ce qu'on se connaît ?",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"C'est une longue histoire. Est-ce que M. Sterling est là ? J'aimerais beaucoup que vous soyez tous présents avant d'expliquer les raisons de ma visite inattendue.",portrait:"portraits/investigator.png"},{speaker:"Rose",text:"Je suis désolée. Mon mari est encore au travail. Il ne devrait plus tarder.",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"Bien, je suppose que je pourrais commencer. La principale personne que je suis venue voir est dans cette pièce.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Lune, il y a quelque chose de très important que je dois te dire.",portrait:"portraits/investigator.png",action:"show_ending_choice"}]},ENDING_1:{title:"La Vérité Révélée",lines:[{speaker:"Delphine",text:"Votre frère. Votre véritable frère est vivant... Mademoiselle Goodwill.",portrait:"portraits/investigator.png"},{speaker:"Lune",text:"Quoi ? Que... Qu'est-ce que vous dites ? Comment connaissez-vous mon...? C'est impossible.",portrait:"portraits/lune_older.png"},{speaker:"Rose",text:"Qui êtes-vous ? Pourquoi dites-vous ces choses horribles ? Nous avons suffisamment souffert et pleuré !",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"Je suis désolée. Je suis vraiment désolée. Cela doit être un choc, mais je... j'ai des preuves. Tenez, lisez cette lettre.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Je suis une... Sensitive. Je peux voir les échos du passé et votre frère m'a engagée pour découvrir ce qui vous était arrivé, à vous et à votre père, Lune. Il pensait que vous aviez tous deux péri cette nuit-là à Bornéo, sinon il vous aurait cherchés plus près de chez lui.",portrait:"portraits/investigator.png"},{speaker:"Lune",text:"Mais Lucas a dit...",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"Il vous a menti, Lune. Il vous a menti à toutes les deux. J'ignore pourquoi, mais il vous a caché cette vérité toutes ces années.",portrait:"portraits/investigator.png"},{speaker:" ",text:"Lucas entre dans la maison."},{speaker:"Lucas",text:"Que... Que se passe-t-il ?",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:" ",text:"Rose jette la lettre au visage de Lucas."},{speaker:"Rose",text:"Quand comptais-tu nous le dire ? Ou n'allais-tu jamais nous le dire ? Comment as-tu pu lui faire ça ?",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:" ",text:"Lucas lit la lettre."},{speaker:"Lucas",text:"Je... Je suis tellement désolé. Je ne voulais pas vous perdre. Je ne voulais pas perdre ça. Je vous aime. Je vous aime tellement toutes les deux.",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"Lune",text:"Je ne comprends pas. Comment peux-tu dire que tu m'aimes et me briser le cœur à ce point ? Tu as vu ce que la perte de mon père et de ma mère m'a fait, et ensuite tu as décidé que ce serait bien de tuer mon frère aussi ?",portrait:"portraits/lune_older.png"},{speaker:"Lucas",text:"J'avais tellement peur de te perdre. C'est ton vrai frère ! Et il a réussi, il est riche et... Je ne suis rien. Je ne mérite aucune de vous deux.",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"Rose",text:"Et moi alors ? Et nous ? Que pensais-tu que cela nous ferait ?",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Lucas",text:"Je ne comprends tout simplement pas pourquoi tu m'aimes, Rose. Je m'attends sans cesse à ce que tu reprennes tes esprits et que tu me quittes. Et si Lune n'avait pas été là, je crains que tu n'aies déjà fait ce choix. J'ai peur que tu ne sois avec moi que par commodité. Tu pourrais trouver tellement mieux que moi.",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"Rose",text:"Tu es fou. Je t'aurais choisi, Lucas. Dans cent pièces, dans cent vies, je t'aurais choisi. Je t'aimais.",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Rose",text:"Mais maintenant...",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Rose",text:"Delphine. Pouvez-vous nous emmener voir le frère de Lune ?... Tout de suite ?",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"Oui, bien sûr.",portrait:"portraits/investigator.png"},{speaker:"Rose",text:"Lune ?",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Lune",text:"Je t'aimais tellement. J'aimais tellement notre famille. Tu as brisé mon cœur, Lucas. J'espère que tu es heureux.",portrait:"portraits/lune_older.png"},{speaker:" ",text:"Lune arrache le collier de son cou. Les perles volent à travers la pièce."},{speaker:"Lune",text:"Je suis prête.",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"Partons. Il nous attend dans un café non loin d'ici.",portrait:"portraits/investigator.png"},{speaker:" ",text:"Lucas ne dit pas un mot en les regardant partir. Il reste simplement là, pleurant de manière incontrôlable."},{speaker:" ",text:"Fin.",action:"credits"}]},ENDING_2:{title:"Un Message de l'Au-delà",lines:[{speaker:"Delphine",text:"Lune, cela va sembler insensé, mais je suis ce qu'on appelle une Sensitive.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Je peux ressentir les échos du passé et les âmes qui n'ont pas encore quitté ce monde. Des fantômes, si vous voulez.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Votre frère... Votre véritable frère, Mademoiselle Goodwill. Il m'a contactée...",portrait:"portraits/investigator.png"},{speaker:"Lune",text:"Quoi ? Que... Qu'est-ce que vous dites ? Comment connaissez-vous mon...? C'est impossible.",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"Depuis l'au-delà. Son âme ne pouvait pas trouver le repos, tant qu'il ne comprenait pas ce qui vous était arrivé.",portrait:"portraits/investigator.png"},{speaker:"Rose",text:"Qui êtes-vous ? Pourquoi dites-vous ces choses horribles ? Nous avons suffisamment souffert et pleuré !",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"Je suis désolée. Je suis vraiment désolée. Cela doit être un choc et je... je n'ai pas de preuves, à part ce journal que j'ai écrit décrivant tout ce qui vous est arrivé depuis cette nuit fatidique à Bornéo.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Comment pourrais-je savoir tout cela, si je n'avais pas les pouvoirs que je prétends avoir ?",portrait:"portraits/investigator.png"},{speaker:" ",text:"Rose et Lune feuillettent le journal, le visage blême de stupeur en lisant le récit de leur vie."},{speaker:"Rose",text:"J'ai du mal à comprendre tout ça. Comment vous a-t-il contactée ?",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"Je pensais avoir reçu une lettre, mais elle n'était pas tout à fait réelle, en fait. D'une certaine manière, j'aurais dû le savoir. Elle est arrivée avec des photos de toutes les personnes présentes dans la plantation à ce moment-là. Je veux dire, comment aurait-il pu obtenir des photos de Kanan et d'Aisyah, par exemple ?...",portrait:"portraits/investigator.png"},{speaker:" ",text:"Rose et Lune dévisagent Delphine, incrédules."},{speaker:"Delphine",text:"Je sais comment ça sonne. Vraiment. J'ai longuement hésité avant même de venir.",portrait:"portraits/investigator.png"},{speaker:" ",text:"Lucas entre dans la maison."},{speaker:"Lucas",text:"Que... Que se passe-t-il ?",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:" ",text:"Lune court vers lui et le serre très fort, en pleurant."},{speaker:"Rose",text:"C'est à propos du... frère de Lune. Cette femme prétend lui avoir parlé.",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"Oh non. Non, je n'ai pas dit que je lui avais parlé, je...",portrait:"portraits/investigator.png"},{speaker:"Lucas",text:"Vous êtes une Sensitive ? Attendez... Vous êtes Delphine ?",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"Delphine",text:"Oui. Nous connaissons-nous déjà ?",portrait:"portraits/investigator.png"},{speaker:"Lucas",text:"Oh non. Pas personnellement. Mais le MI6 vous a employée par le passé. Vous avez fait un travail remarquable pour nous... et pour le pays. Je vous remercie du fond du cœur.",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"Delphine",text:"Merci. Cela me touche beaucoup.",portrait:"portraits/investigator.png"},{speaker:"Rose",text:"Attendez. Donc, tout ce qu'elle nous raconte est vrai ?",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Lucas",text:"Après ce que j'ai vu et entendu, je ne douterais de rien de ce qu'elle dit.",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:" ",text:"Lune se remet de son choc initial et prend enfin la parole."},{speaker:"Lune",text:"Donc vous dites que mon frère tenait tellement à moi qu'il n'a pas pu trouver le repos avant d'avoir découvert la vérité ?",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"Oui, c'est ce que je dis. Et au moment où il a découvert que vous étiez en vie, heureuse et que vous viviez votre vie, l'écho de la lettre qu'il m'avait envoyée s'est évanoui et je l'ai senti partir, enfin en paix.",portrait:"portraits/investigator.png"},{speaker:" ",text:"Le silence s'installe dans la pièce pendant un moment inconfortablement long."},{speaker:"Rose",text:"Du thé ! Où sont mes bonnes manières, voulez-vous du thé ?",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"Delphine",text:"Ce serait merveilleux.",portrait:"portraits/investigator.png"},{speaker:" ",text:"Ils s'asseyent tous dans le salon."},{speaker:"Delphine",text:"Ai-je bien fait ? Ai-je fait le bon choix en venant ici ? Ou aurais-je dû vous laisser dans votre heureuse ignorance ?",portrait:"portraits/investigator.png"},{speaker:" ",text:"Lune essuie une larme du coin de l'œil. C'est une larme de joie."},{speaker:"Lune",text:"Vous avez fait le bon choix, Delphine. Cela m'a enfin permis de tourner la page. Merci.",portrait:"portraits/lune_older.png"},{speaker:"Delphine",text:"Oh, et avant que je n'oublie !",portrait:"portraits/investigator.png"},{speaker:" ",text:"Delphine sort quelque chose de sa poche."},{speaker:"Delphine",text:"Je suis allée voir Mademoiselle Seville avant de venir ici, voyez-vous. Juste pour savoir si je devais venir ou non, vous comprenez ?",portrait:"portraits/investigator.png"},{speaker:"Lucas",text:"Oh, Cynthia est de retour au pays ?",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"Delphine",text:"Oui, mais seulement pour une courte période et c'est très confidentiel. Personne ne devrait savoir où elle est, mais vous savez, j'ai mes méthodes.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Bref, Lune. Elle voulait que vous ayez ça.",portrait:"portraits/investigator.png"},{speaker:" ",text:"Delphine tend une unique perle rouge à Lune."},{speaker:"Delphine",text:`"En souvenir, pour que nous n'oubliions jamais", voilà ce qu'elle m'a dit.`,portrait:"portraits/investigator.png"},{speaker:" ",text:"Lune accroche la perle rouge à l'avant de son collier. Un sourire radieux illumine son visage."},{speaker:" ",text:"Fin.",action:"credits"}]},ROOM_EPIPHANY:{title:"Échos Complets",lines:[{speaker:"Delphine",text:"Mon instinct me dit que j'ai découvert tout ce qu'il y avait à voir dans ce lieu. Les heures restantes ne cachent plus aucun secret.",portrait:"portraits/investigator.png"}]},BOAT_TUTORIAL:{title:"Le Hangar à Bateaux",lines:[{speaker:"Delphine",text:"Donc Jeremiah a dit que Kanan interrogeait Lucas au hangar à bateaux. Je suppose que cela était déjà en cours avant que Jeremiah ne passe son appel.",portrait:"portraits/investigator.png"},{speaker:" ",text:"Si Delphine sélectionne Lucas et Kanan et se concentre à 15:00, elle devrait pouvoir découvrir l'écho de cette interaction."}]},BOAT_TUTORIAL_EMPTY:{title:"Le Hangar à Bateaux",lines:[{speaker:"Delphine",text:"Je n'ai pas encore tout ce qu'il me faut pour découvrir des échos ici. Je dois parcourir la liste des invités et découvrir qui sont certains d'entre eux.",portrait:"portraits/investigator.png"}]},TIDAK_APA:{title:"Tidak Apa",theme:"jargon",lines:[{speaker:"Delphine",text:"Tidak apa signifie 'ça ne fait rien' ou 'peu importe' en malais.",portrait:"portraits/investigator.png"}]},CYNTHIA_JOURNEY:{title:"Le Voyage de Cynthia",lines:[{speaker:"Delphine",text:"Je me demande comment s'est passé le voyage de Cynthia. Je sais que mon bienfaiteur n'a ni le besoin ni l'envie d'avoir ces informations, mais Mademoiselle Seville pourrait encore m'être utile.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Je devrais probablement prendre de ses nouvelles. Je suis sûre que je peux ressentir son voyage par la pensée si je me concentre.",portrait:"portraits/investigator.png"}]},MANIFEST:{lines:[{speaker:"Delphine",text:"Il y a des photos du personnel clé. Je peux deviner, grâce à la résonance que je ressens, lesquels seront importants. Je vais les ajouter au dossier.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Je ne peux les ressentir qu'à partir de 8h00, le mercredi matin. Leur chaloupe devait être trop éloignée de la plantation avant cela et, de toute façon, je n'aurais pas su d'où en mer elle aurait émergé.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Il est également très clair qu'ils étaient tous ensemble sur le rivage à 8h00 et qu'ils se sont dispersés ensuite.",portrait:"portraits/investigator.png"}]},PEARL_2:{lines:[{speaker:"Delphine",text:"Celui à qui appartient un objet peut parfois être trompeur. La perle devrait théoriquement appartenir à Bone ou à Jeremiah, mais elle a été avec Cynthia pendant si longtemps qu'elle est imprégnée de son essence.",portrait:"portraits/investigator.png"}]},SAMPAN:{lines:[{speaker:"Delphine",text:"Une pirogue locale creusée dans un tronc.",portrait:"portraits/investigator.png"}]},PARANG:{lines:[{speaker:"Delphine",text:"Le couteau dont on se sert à tout faire et l'arme typique des tropiques. Il est spécialement conçu pour la végétation dense et ligneuse de la jungle primaire.",portrait:"portraits/investigator.png"}]},CHARLESBROOKE:{lines:[{speaker:"Delphine",text:"Charles Brooke. Ce nom me dit quelque chose. Où l'ai-je déjà vu ? Je suis sûre de l'avoir vu quelque part pendant mes recherches sur Bornéo. Peut-être dans mon glossaire sur les colonies ?",portrait:"portraits/investigator.png"}]},WHITERAJAH:{lines:[{speaker:"Delphine",text:"Oui, là ! C'est le Rajah Blanc ! Et j'ai aussi une photo, comme c'est pratique.",portrait:"portraits/investigator.png",trigger:"reveal:p21"}]},IBAN:{lines:[{speaker:"Delphine",text:"Les guerriers Iban étaient les guerriers les plus légendaires et les plus redoutés de l'archipel malais. Alors que les Britanniques et les Hollandais apportaient bateaux à vapeur et télégraphes, les Ibans restaient les maîtres du paysage de Bornéo, un peuple dont la culture était fondée sur le fleuve et une tradition de guerre dans la jungle.",portrait:"portraits/investigator.png"}]},DUSUN:{lines:[{speaker:"Delphine",text:"Le peuple Dusun est le groupe indigène le plus important du nord de Bornéo ; ce sont des fermiers et de féroces chasseurs.",portrait:"portraits/investigator.png"}]},BATU:{title:"Batu Sapi",lines:[{speaker:"Delphine",text:"Batu Sapi est une zone côtière à Sandakan reconnue pour une formation rocheuse naturelle à trois pattes en forme de buffle créée par l'érosion. Situé près de la plage de Karamunting, ce point de repère est imprégné de la légende locale, où l'on pense qu'il s'agit du corps transformé d'un buffle héroïque qui a combattu un crocodile pour sauver un village local.",portrait:"portraits/investigator.png"}]},JUBILEE:{lines:[{speaker:"Delphine",text:"La tour de l'horloge du jubilé de Sandakan était un monument historique situé à Sandakan. C'était une structure remarquable du Bornéo du Nord britannique colonial ; elle a survécu à la guerre, mais a été démolie peu de temps après lors de la reconstruction de la ville.",portrait:"portraits/investigator.png"}]},CHINESETOWN:{lines:[{speaker:"Delphine",text:"Chinese Town was the commercial heart of Sandakan, a bustling district of shophouses and markets where the local Chinese community conducted their businesses. It was a vibrant hub of activity, with the sounds of commerce and the aroma of spices filling the air. ",portrait:"portraits/investigator.png"}]},MIND_EYE:{lines:[{speaker:"Delphine",text:"Quelque chose s'est éveillé dans mon troisième œil. Je devrais aller voir de quoi il s'agit.",portrait:"portraits/investigator.png"}]},CYNTHIA_ENDING:{lines:[{speaker:"Delphine",text:"Je sais maintenant ce qui est arrivé à Cynthia. Elle a fui Sandakan avec le Rapport Mist et a réussi à atteindre Ceylan. Je me demande si elle est encore en vie ? Je devrais essayer de la contacter pour avoir sa version de l'histoire.",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"Mais pour l'instant, je peux clore ce chapitre.",portrait:"portraits/investigator.png"}]},POST_CREDITS:{lines:[{speaker:" ",text:"Février 1964"},{speaker:" ",text:"On frappe à la porte d'entrée."},{speaker:"Delphine",text:"Qui cela peut-il être ?",portrait:"portraits/investigator.png"},{speaker:"Delphine",text:"J'arrive !",portrait:"portraits/investigator.png"},{speaker:"Cynthia",text:"Bonjour, Delphine.",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:"Delphine",text:"Agent Seville ? Qu'est-ce qui vous amène ici ?",portrait:"portraits/investigator.png"},{speaker:"Cynthia",text:"Je suis en danger et je ne sais plus à qui me fier. J'ai besoin de votre aide.",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:"Delphine",text:"Qu'est-ce qui ne va pas ? Que se passe-t-il ?",portrait:"portraits/investigator.png"},{speaker:"Cynthia",text:"L'un de nos meilleurs agents, qui est aussi un ami très cher, a disparu.",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:"Cynthia",text:"La dernière fois que je lui ai parlé, il a dit qu'il était sur une affaire importante, mais qu'il était suivi.",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:"Cynthia",text:"Je suis morte d'inquiétude, mais je crains le pire, et que quelqu'un de l'intérieur soit responsable.",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:"Delphine",text:"Je suis désolée d'entendre ça. Comment s'appelait-il ?",portrait:"portraits/investigator.png"},{speaker:"Cynthia",text:"Il s'appelle Arthur. Arthur Birdwhistle.",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:" ",text:" ",action:"tbc"}]},TOO_SOON:{title:"Piste Interrompue",lines:[{speaker:"Delphine",text:"Je vois que vous avez déjà trouvé des traces d'elle dans la chapelle à 17h00, mais je n'ai pas encore assez d'informations pour suivre la piste au-delà de cette heure. Je devrais revenir plus tard.",portrait:"portraits/investigator.png"}]}};export{t as DIALOGUE};
